--DW_GROUPS_HEALTHCARE_V		
SELECT GROUP_ID, LDAP_HOST, LDAP_OU, GROUP_NAME, PRIMARY_MANAGER_SSO, ATTR_GEAPPNAME, ATTR_GECPASECURITYGROUP, ATTR_GECPAGROUPECSTATUS
FROM IDM.DW_IDM_GROUP G
JOIN IDM_USER U ON G.PRIMARY_MANAGER_SSO = U.PERSON_NUM_SSO
WHERE U.INDUSTRY_FOCUS_NAME = 'GE Healthcare'

--DW_GROUP_AUDIT_DATA_POWER_V
SELECT "ID", "GROUP_NAME", "GROUP_ID", "PRIMARY_MANAGER_SSO", "PRIMARY_MANAGER_BUSINESS", "AUDIT_EVENT_CREATED", "SOURCE", "ACTION", "INSTANCE", "ATTRIBUTE_NAME", "ATTRIBUTES" 
FROM IDM.DW_GROUP_AUDIT_DATA
WHERE PRIMARY_MANAGER_BUSINESS IN ('GE Power', 'GE Power Portfolio', 'GE Gas Power')

--DW_GROUP_AVIATION_V
SELECT G."GROUP_ID", G."LDAP_HOST", G."LDAP_OU", G."GROUP_NAME", G."PRIMARY_MANAGER_SSO", G."ATTR_GEAPPNAME", G."ATTR_GECPASECURITYGROUP", G."ATTR_GECPAGROUPECSTATUS"
FROM IDM.DW_IDM_GROUP G
LEFT JOIN IDM.IDM_user U ON G.PRIMARY_MANAGER_SSO = U.PERSON_NUM_SSO
WHERE U.INDUSTRY_FOCUS_ID IS NOT NULL
AND U.INDUSTRY_FOCUS_ID = '1178320'

--DW_GROUP_MANAGER_AVIATION_V		
SELECT GMGR."GROUP_ID", GMGR."MANAGER", U.FIRST_NAME, U.LAST_NAME, U.EMAIL_ADDRESS, U.MANAGER_PERSON_NUM, U.PERSON_STATUS
FROM IDM.DW_IDM_GROUP_MANAGER GMGR
JOIN IDM.DW_GROUP_AVIATION_V G ON GMGR.GROUP_ID = G.GROUP_ID -- DW_GROUP_AVIATION_G only presents GROUPS with Primary Managers in AVIATION
LEFT JOIN IDM.IDM_USER U ON GMGR.MANAGER = U.PERSON_NUM_SSO

--DW_GROUP_MANAGER_VERNOVA_V		
SELECT GMGR."GROUP_ID", GMGR."MANAGER", U.FIRST_NAME, U.LAST_NAME, U.EMAIL_ADDRESS, U.MANAGER_PERSON_NUM, U.PERSON_STATUS
FROM IDM.DW_IDM_GROUP_MANAGER GMGR
JOIN IDM.DW_GROUP_VERNOVA_V G ON GMGR.GROUP_ID = G.GROUP_ID -- DW_GROUP_VERNOVA_G only presents GROUPS with Primary Managers in Vernova
LEFT JOIN IDM.IDM_USER U ON GMGR.MANAGER = U.PERSON_NUM_SSO

--DW_GROUP_MEMBER_AVIATION_V		
SELECT GM."GROUP_ID", GM."MEMBER", U.FIRST_NAME, U.LAST_NAME, U.EMAIL_ADDRESS, U.MANAGER_PERSON_NUM, U.PERSON_STATUS
FROM IDM.DW_IDM_GROUP_MEMBER GM
JOIN IDM.DW_GROUP_AVIATION_V G ON GM.GROUP_ID = G.GROUP_ID -- DW_GROUP_AVIATION_G only presents GROUPS with Primary Managers in AVIATION
LEFT JOIN IDM.IDM_USER U ON GM.MEMBER=U.PERSON_NUM_SSO

--DW_GROUP_MEMBER_VERNOVA_V		
SELECT GM."GROUP_ID", GM."MEMBER", U.FIRST_NAME, U.LAST_NAME, U.EMAIL_ADDRESS, U.MANAGER_PERSON_NUM, U.PERSON_STATUS
FROM IDM.DW_IDM_GROUP_MEMBER GM
JOIN IDM.DW_GROUP_VERNOVA_V G ON GM.GROUP_ID = G.GROUP_ID -- DW_GROUP_VERNOVA_G only presents GROUPS with Primary Managers in Vernova
LEFT JOIN IDM.IDM_USER U ON GM.MEMBER=U.PERSON_NUM_SSO

