--DW_GROUP_VERNOVA_V		
SELECT G."GROUP_ID", G."LDAP_HOST", G."LDAP_OU", G."GROUP_NAME", G."PRIMARY_MANAGER_SSO", G."ATTR_GEAPPNAME", G."ATTR_GECPASECURITYGROUP", G."ATTR_GECPAGROUPECSTATUS"
FROM IDM.DW_IDM_GROUP G
LEFT JOIN IDM.IDM_USER U ON G.PRIMARY_MANAGER_SSO = U.PERSON_NUM_SSO
WHERE U.INDUSTRY_FOCUS_ID IS NOT NULL
    AND U.INDUSTRY_FOCUS_ID <> '1178477'
    AND U.INDUSTRY_FOCUS_ID <> '1178320'

--DW_USER_CHANGE_EVENTS_VERNOVA_V		
SELECT CL."IDM_USER_CHANGE_EVENT_ID", CL."PERSON_NUM_SSO", CL."EVENT_TYPE", CL."PERSON_STATUS", CL."PERSON_STATUS_OLD", CL."GEHRLOCATIONID", CL."GEHRLOCATIONID_OLD", CL."INDUSTRY_FOCUS_ID", CL."INDUSTRY_FOCUS_ID_OLD", CL."GEHRJOBID", CL."GEHRJOBID_OLD", CL."MANAGER_PERSON_NUM", CL."MANAGER_PERSON_NUM_OLD", CL."NEW_MANAGER_DETAILS", CL."OLD_MANAGER_DETAILS", CL."FIRST_NAME", CL."FIRST_NAME_OLD", CL."LAST_NAME", CL."LAST_NAME_OLD", CL."BUSINESS_SEGMENT_ID", CL."BUSINESS_SEGMENT_ID_OLD", CL."BUSINESS_SEGMENT_NAME", CL."BUSINESS_SEGMENT_NAME_OLD", CL."CITY", CL."CITY_OLD", CL."COUNTRY", CL."COUNTRY_OLD", CL."DEPARTMENT_NAME", CL."DEPARTMENT_NAME_OLD", CL."DIVISIONID", CL."DIVISIONID_OLD", CL."DIVISION_NAME", CL."DIVISION_NAME_OLD", CL."EMAIL_ADDRESS", CL."EMAIL_ADDRESS_OLD", CL."EMAIL_DISPLAY_NAME", CL."EMAIL_DISPLAY_NAME_OLD", CL."BU_NUMBER", CL."BU_NUMBER_OLD", CL."GRADE_BAND", CL."GRADE_BAND_OLD", CL."INDUSTRY_FOCUS_NAME", CL."INDUSTRY_FOCUS_NAME_OLD", CL."JOB_TITLE", CL."JOB_TITLE_OLD", CL."PERSON_TYPE", CL."PERSON_TYPE_OLD", CL."SSO_EXPIRATION_DATE", CL."SSO_EXPIRATION_DATE_OLD", CL."STATE", CL."STATE_OLD", CL."WORKER_TYPE", CL."WORKER_TYPE_OLD", CL."WORK_PHONE", CL."WORK_PHONE_OLD", CL."PROCESS_STATUS", CL."EXTN1", CL."EXTN2", CL."CREATION_DATE", CL."LAST_UPDATE_DATE", CL."MIDDLE_NAME", CL."MIDDLE_NAME_OLD", CL."GEHRASSIGNMENTSTATUS", CL."GEHRASSIGNMENTSTATUS_OLD", CL."GEHRPOSITIONID", CL."GEHRPOSITIONID_OLD"
FROM IDM.IDM_USER_CHANGE_EVENT_LOG CL
INNER JOIN IDM.DW_IDENTITY_VERNOVA_V I ON CL.PERSON_NUM_SSO = I.PERSON_NUM_SSO
WHERE CL.LAST_UPDATE_DATE >= ADD_MONTHS(TRUNC(SYSDATE), -12)

-- CHANGE EVENTS FOR CoreTech
SELECT CL."IDM_USER_CHANGE_EVENT_ID", CL."PERSON_NUM_SSO", CL."EVENT_TYPE", CL."PERSON_STATUS", CL."PERSON_STATUS_OLD", CL."GEHRLOCATIONID", CL."GEHRLOCATIONID_OLD", CL."INDUSTRY_FOCUS_ID", CL."INDUSTRY_FOCUS_ID_OLD", CL."GEHRJOBID", CL."GEHRJOBID_OLD", CL."MANAGER_PERSON_NUM", CL."MANAGER_PERSON_NUM_OLD", CL."NEW_MANAGER_DETAILS", CL."OLD_MANAGER_DETAILS", CL."FIRST_NAME", CL."FIRST_NAME_OLD", CL."LAST_NAME", CL."LAST_NAME_OLD", CL."BUSINESS_SEGMENT_ID", CL."BUSINESS_SEGMENT_ID_OLD", CL."BUSINESS_SEGMENT_NAME", CL."BUSINESS_SEGMENT_NAME_OLD", CL."CITY", CL."CITY_OLD", CL."COUNTRY", CL."COUNTRY_OLD", CL."DEPARTMENT_NAME", CL."DEPARTMENT_NAME_OLD", CL."DIVISIONID", CL."DIVISIONID_OLD", CL."DIVISION_NAME", CL."DIVISION_NAME_OLD", CL."EMAIL_ADDRESS", CL."EMAIL_ADDRESS_OLD", CL."EMAIL_DISPLAY_NAME", CL."EMAIL_DISPLAY_NAME_OLD", CL."BU_NUMBER", CL."BU_NUMBER_OLD", CL."GRADE_BAND", CL."GRADE_BAND_OLD", CL."INDUSTRY_FOCUS_NAME", CL."INDUSTRY_FOCUS_NAME_OLD", CL."JOB_TITLE", CL."JOB_TITLE_OLD", CL."PERSON_TYPE", CL."PERSON_TYPE_OLD", CL."SSO_EXPIRATION_DATE", CL."SSO_EXPIRATION_DATE_OLD", CL."STATE", CL."STATE_OLD", CL."WORKER_TYPE", CL."WORKER_TYPE_OLD", CL."WORK_PHONE", CL."WORK_PHONE_OLD", CL."PROCESS_STATUS", CL."EXTN1", CL."EXTN2", CL."CREATION_DATE", CL."LAST_UPDATE_DATE", CL."MIDDLE_NAME", CL."MIDDLE_NAME_OLD", CL."GEHRASSIGNMENTSTATUS", CL."GEHRASSIGNMENTSTATUS_OLD", CL."GEHRPOSITIONID", CL."GEHRPOSITIONID_OLD"
FROM IDM.IDM_USER_CHANGE_EVENT_LOG CL
INNER JOIN IDM.DW_IDENTITY I ON CL.PERSON_NUM_SSO = I.IDENTITY 
WHERE CL.LAST_UPDATE_DATE >= ADD_MONTHS(TRUNC(SYSDATE), -2)


--DW_USER_DELEGATION_VERNOVA_V		
SELECT SI.NAME, SI.FIRSTNAME, SI.LASTNAME, SI.EMAIL, EXTRACTVALUE(XMLTYPE(SI.PREFERENCES), '/Map/entry[@key="forward"]/@value') AS "Delegate SSO"
    , EST(EXTRACTVALUE(XMLTYPE(SI.PREFERENCES), '/Map/entry[@key="forwardStartDate"]/value/Date')) AS "Delegate Start Date"
    , EST(EXTRACTVALUE(XMLTYPE(SI.PREFERENCES), '/Map/entry[@key="forwardEndDate"]/value/Date')) AS "Delegate End Date"
FROM (
    SELECT * FROM sp.spt_identity 
    WHERE extended6='A' 
        AND PREFERENCES LIKE '%forward%'
) SI
INNER JOIN IDM.DW_IDENTITY_VERNOVA_V VI ON SI.NAME=VI.PERSON_NUM_SSO
ORDER by 'Delegate End Date' DESC

